-- Import data prasarana olahraga Kota Tangerang Selatan
-- Generated dari file Excel yang di-upload, 15 baris data
-- Jalankan di Supabase SQL Editor: Project > SQL Editor > New Query > paste > Run

CREATE TABLE IF NOT EXISTS prasarana_olahraga (
    id SERIAL PRIMARY KEY,
    nama_prasarana TEXT NOT NULL,
    olahraga TEXT NOT NULL,
    alamat TEXT,
    kecamatan TEXT NOT NULL,
    google_maps_link TEXT,
    status TEXT DEFAULT 'Aktif',
    link_gambar_1 TEXT,
    link_gambar_2 TEXT,
    link_gambar_3 TEXT,
    created_at TIMESTAMPTZ DEFAULT now(),
    UNIQUE (nama_prasarana, olahraga)
);

